#include <stdio.h>
#include <stdbool.h>

#define MAX_BLOCKS 10

typedef struct {
 int size;
 bool allocated;
} Block;

Block memory[MAX_BLOCKS];
int numBlocks;

void initMemory() {
 int sizes[] = {100, 500, 200, 300, 600};
 numBlocks = 5;
 for (int i = 0; i < numBlocks; i++) {
 memory[i].size = sizes[i];
 memory[i].allocated = false;
 }
}

int firstFit(int processSize) {
 for (int i = 0; i < numBlocks; i++) {
 if (!memory[i].allocated && memory[i].size >= processSize) {
 memory[i].allocated = true;
 printf("First Fit: Process (%d) -> Block %d (%d)\n",
 processSize, i, memory[i].size);
 return i;
 }
 }
 return -1; // No fit
}

int bestFit(int processSize) {
 int bestIdx = -1, minDiff = 99999;

 for (int i = 0; i < numBlocks; i++) {
 if (!memory[i].allocated && memory[i].size >= processSize) {
 int diff = memory[i].size - processSize;
 if (diff < minDiff) {
 minDiff = diff;
 bestIdx = i;
 }
 }
 }

 if (bestIdx != -1) {
 memory[bestIdx].allocated = true;
 printf("Best Fit: Process (%d) -> Block %d (%d)\n",
 processSize, bestIdx, memory[bestIdx].size);
 }
 return bestIdx;
}

int worstFit(int processSize) {
 int worstIdx = -1, maxSize = -1;

 for (int i = 0; i < numBlocks; i++) {
 if (!memory[i].allocated && memory[i].size >= processSize) {
 if (memory[i].size > maxSize) {
 maxSize = memory[i].size;
 worstIdx = i;
 }
 }
 }

 if (worstIdx != -1) {
 memory[worstIdx].allocated = true;
 printf("Worst Fit: Process (%d) -> Block %d (%d)\n",
 processSize, worstIdx, memory[worstIdx].size);
 }
 return worstIdx;
}

int main() {
 initMemory();
 printf("\nTesting First Fit:\n");
 firstFit(212);
 firstFit(417);
 firstFit(112);

 return 0;
}

class MemoryBlock:
 def __init__(self, size):
 self.size = size
 self.allocated = False

def first_fit(memory, process_size):
 """Allocate first block that fits"""
 for i, block in enumerate(memory):
 if not block.allocated and block.size >= process_size:
 block.allocated = True
 print(f"First Fit: Process({process_size}) -> Block {i} ({block.size})")
 return i
 print(f"First Fit: No block found for process {process_size}")
 return -1

def best_fit(memory, process_size):
 """Allocate smallest block that fits"""
 best_idx = -1
 min_diff = float('inf')

 for i, block in enumerate(memory):
 if not block.allocated and block.size >= process_size:
 diff = block.size - process_size
 if diff < min_diff:
 min_diff = diff
 best_idx = i

 if best_idx != -1:
 memory[best_idx].allocated = True
 print(f"Best Fit: Process({process_size}) -> Block {best_idx} ({memory[best_idx].size})")
 return best_idx

def worst_fit(memory, process_size):
 """Allocate largest block that fits"""
 worst_idx = -1
 max_size = -1

 for i, block in enumerate(memory):
 if not block.allocated and block.size >= process_size:
 if block.size > max_size:
 max_size = block.size
 worst_idx = i

 if worst_idx != -1:
 memory[worst_idx].allocated = True
 print(f"Worst Fit: Process({process_size}) -> Block {worst_idx} ({memory[worst_idx].size})")
 return worst_idx

