import java.util.*;

public class MemoryAllocation {
 static class Block {
 int size;
 boolean allocated;
 Block(int size) { this.size = size; }
 }

 static int firstFit(Block[] memory, int processSize) {
 for (int i = 0; i < memory.length; i++) {
 if (!memory[i].allocated && memory[i].size >= processSize) {
 memory[i].allocated = true;
 System.out.printf("First Fit: Process(%d) -> Block %d (%d)%n",
 processSize, i, memory[i].size);
 return i;
 }
 }
 return -1;
 }

 static int bestFit(Block[] memory, int processSize) {
 int bestIdx = -1, minDiff = Integer.MAX_VALUE;

 for (int i = 0; i < memory.length; i++) {
 if (!memory[i].allocated && memory[i].size >= processSize) {
 int diff = memory[i].size - processSize;
 if (diff < minDiff) {
 minDiff = diff;
 bestIdx = i;
 }
 }
 }

 if (bestIdx != -1) {
 memory[bestIdx].allocated = true;
 System.out.printf("Best Fit: Process(%d) -> Block %d (%d)%n",
 processSize, bestIdx, memory[bestIdx].size);
 }
 return bestIdx;
 }

 public static void main(String[] args) {
 int[] sizes = {100, 500, 200, 300, 600};
 Block[] memory = new Block[sizes.length];
 for (int i = 0; i < sizes.length; i++)
 memory[i] = new Block(sizes[i]);

 System.out.println("Testing First Fit:");
 firstFit(memory, 212);
 firstFit(memory, 417);
 }
}
